  ('pukao-6e11b43e-moex-00211', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-112-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '關於「行政倫理」之敘述，下列何者錯誤？', '["我國目前對於公共行政者倫理行為的要求，企圖兼顧防弊與興利", "公務員服務法屬於對公務人員之政治行為的規範", "我國目前尚無公共服務倫理的專法，各項規範散見於不同法規中", "公務人員行政中立法的規範對象是法定機關依法任用、派用的有給專任人員及公立學校依法任用的職員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00212', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-112-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '具備廣泛社會代表性的官僚可實現下列何種目標？', '["降低對代議士依賴", "提升行政立法制衡", "有助於分配性正義", "回應菁英階層利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00213', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-112-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '多年前發生之八掌溪事件主因在於各級機關分工協調不佳和相互卸責，這是行政課責所討論的何種議題？', '["左右為難（catch-22）", "髒手（dirtyhands）", "多手（manyhands）", "組織擴增（organizationalenlargement）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00214', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-112-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '下列何者為矩陣組織的運作特徵？', '["通常為常設性組織編制", "僅需服從單一權威命令", "較無助於培養通才能力", "為解決特定任務而設立"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00215', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-112-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '下列針對組織中權力之敘述，何者正確？', '["平行部門之間的相對權力大小，隨著組織所面臨的問題而有所調整", "平行部門之間，接受資源的單位，其權力通常大於控制資源的單位", "組織中的基層人員，其權力基礎在於組織整體資源的分配", "在組織中，個人被替代性越高，權力越大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00216', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-112-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '下列針對組織內部部門之間的衝突，何者錯誤？', '["部門之間的目標越不相容，越容易產生衝突", "部門之間在工作上互相依賴的程度越高，越不容易有衝突", "部門之間越需要互相競爭以爭取有限的資源，越容易產生衝突", "部門之間若職掌清楚，互動有法規或前例可循，比較不容易產生衝突"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00217', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-112-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '有關組織中非正式團體之敘述，下列何者錯誤？', '["非正式團體的存在，有時使組織內的溝通更有效率", "非正式團體本身的凝聚力強，可能會形成組織內的派系之爭", "非正式團體提供所屬成員的情感依歸", "非正式團體是組織中權威的基礎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "64bf518f70b8", "answer_pdf_sha1": "7ce0a260f6de", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
